-- الخطوة 1: إضافة أعمدة جديدة إلى جدول inclusion_plans
ALTER TABLE inclusion_plans ADD COLUMN IF NOT EXISTS manhel_id TEXT;
ALTER TABLE inclusion_plans ADD COLUMN IF NOT EXISTS section TEXT;
ALTER TABLE inclusion_plans ADD COLUMN IF NOT EXISTS special_ed_teacher TEXT;
ALTER TABLE inclusion_plans ADD COLUMN IF NOT EXISTS plan_type TEXT;
ALTER TABLE inclusion_plans ADD COLUMN IF NOT EXISTS academic_year TEXT DEFAULT '2025-2026';

-- الخطوة 2: حذف البيانات القديمة إن وجدت (لتجنب التكرار)
DELETE FROM inclusion_plans WHERE academic_year = '2025-2026';

-- الخطوة 3: إدراج 107 طالب

-- التحقق
SELECT COUNT(*) as total, class_name, plan_type FROM inclusion_plans WHERE academic_year='2025-2026' GROUP BY class_name, plan_type ORDER BY class_name;